#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding contraception-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    relationship_status:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_reproductive_history \
    assessment:references \
    gravida:int \
    para:int \
    miscarriages:int \
    terminations:int \
    ectopic_pregnancies:int \
    last_delivery_date:date \
    last_delivery_method:string! \
    breastfeeding:string! \
    weeks_postpartum:int \
    currently_pregnant:string! \
    pregnancy_test_date:date \
    pregnancy_test_result:string! \
    reproductive_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_menstrual_history \
    assessment:references \
    age_at_menarche:int \
    last_menstrual_period:date \
    cycle_regularity:string! \
    cycle_length_days:int \
    period_duration_days:int \
    flow_heaviness:string! \
    intermenstrual_bleeding:string! \
    postcoital_bleeding:string! \
    dysmenorrhoea:string! \
    dysmenorrhoea_management:text! \
    menstrual_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_contraception \
    assessment:references \
    currently_using_contraception:string! \
    current_method:string! \
    current_method_details:text! \
    current_method_duration_months:int \
    satisfaction_with_current:string! \
    reason_for_change:text! \
    side_effects_experienced:text! \
    previous_methods_tried:text! \
    previous_method_problems:text! \
    emergency_contraception_used:string! \
    emergency_contraception_details:text! \
    current_contraception_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    history_of_vte:string! \
    vte_details:text! \
    history_of_stroke:string! \
    history_of_mi:string! \
    migraine_with_aura:string! \
    migraine_without_aura:string! \
    hypertension:string! \
    systolic_bp_mmhg:int \
    diastolic_bp_mmhg:int \
    diabetes:string! \
    diabetes_complications:string! \
    liver_disease:string! \
    liver_disease_details:text! \
    gallbladder_disease:string! \
    breast_cancer:string! \
    breast_cancer_details:text! \
    cervical_cancer:string! \
    endometriosis:string! \
    fibroids:string! \
    pelvic_inflammatory_disease:string! \
    sti_history:string! \
    sti_details:text! \
    epilepsy:string! \
    epilepsy_medications:text! \
    current_medications:text! \
    drug_allergies:text! \
    medical_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_cardiovascular_risk \
    assessment:references \
    smoking_status:string! \
    cigarettes_per_day:int \
    age_over_35_and_smoking:string! \
    bmi:double \
    bmi_over_35:string! \
    family_history_vte:string! \
    family_vte_details:text! \
    family_history_arterial_disease:string! \
    family_arterial_details:text! \
    known_thrombophilia:string! \
    thrombophilia_type:string! \
    immobility_risk:string! \
    immobility_details:text! \
    major_surgery_planned:string! \
    cardiovascular_risk_notes:text! \
    --htmx

cargo loco generate scaffold assessment_lifestyle_factors \
    assessment:references \
    alcohol_consumption:string! \
    alcohol_units_per_week:int \
    recreational_drug_use:string! \
    recreational_drug_details:text! \
    exercise_frequency:string! \
    occupation:string! \
    shift_work:string! \
    travel_frequency:string! \
    sexual_activity_frequency:string! \
    number_of_partners:string! \
    condom_use_for_sti_prevention:string! \
    lifestyle_notes:text! \
    --htmx

cargo loco generate scaffold assessment_preferences_priorities \
    assessment:references \
    most_important_factor:string! \
    most_important_factor_other:text! \
    preference_for_hormonal:string! \
    preference_for_long_acting:string! \
    comfortable_with_procedure:string! \
    wants_period_control:string! \
    fertility_timeline:string! \
    partner_involvement:string! \
    partner_preferences:text! \
    previous_method_preferences:text! \
    preferences_notes:text! \
    --htmx

cargo loco generate scaffold assessment_breast_cervical_screening \
    assessment:references \
    last_cervical_smear_date:date \
    cervical_smear_result:string! \
    cervical_smear_abnormality_details:text! \
    hpv_vaccination_status:string! \
    breast_self_examination:string! \
    last_mammogram_date:date \
    mammogram_result:string! \
    mammogram_abnormality_details:text! \
    breast_lumps_or_changes:string! \
    breast_change_details:text! \
    screening_notes:text! \
    --htmx

cargo loco generate scaffold assessment_family_planning_goals \
    assessment:references \
    desired_number_of_children:int \
    children_already_have:int \
    considering_sterilisation:string! \
    sterilisation_discussed:string! \
    vasectomy_considered:string! \
    preconception_counselling_needed:string! \
    folic_acid_advised:string! \
    fertility_concerns:string! \
    fertility_concern_details:text! \
    method_chosen:string! \
    method_chosen_details:text! \
    follow_up_plan:text! \
    family_planning_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    overall_highest_ukmec_category:int! \
    ukmec_cocp:int \
    ukmec_pop:int \
    ukmec_patch:int \
    ukmec_ring:int \
    ukmec_injection:int \
    ukmec_implant:int \
    ukmec_cu_iud:int \
    ukmec_lng_ius:int \
    ukmec_condom_male:int \
    ukmec_condom_female:int \
    ukmec_diaphragm:int \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
